//! # MegaDepth Validator — Sovereign Perspective Consensus
//!
//! Validates the Holographic Reconstruction by simulating multi-view
//! ingestion of a real-world landmark (St. Peter's Facade).
//!
//! PROOF OF CONSENSUS:
//! 1. Feed 2 "Truth" views from different angles.
//! 2. Feed 1 "Saboteur" view (intentionally misaligned/offset).
//! 3. The Sovereign Sieve must discard the Saboteur's noise and
//!    validate the landmark shape through projective intersection.

use distributed_inference::holographic_reconstruction::{
    ProjectionView, SovereignSieve, VirtualShutter, VoxelCoord,
};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!(" [ MEGADEPTH VALIDATOR: SOVEREIGN PERSPECTIVE CONSENSUS ] ");

    let mut sieve = SovereignSieve::new(40, 40, 40);
    let center = VoxelCoord {
        x: 20,
        y: 20,
        z: 20,
    };
    let width = 80;
    let height = 40;

    // --- LANDMARK TRUTH ---
    // A simplified facade: a 10x20 wall at y=15
    let mut truth_voxels = Vec::new();
    for x in 15..25 {
        for z in 10..30 {
            truth_voxels.push(VoxelCoord { x, y: 15, z });
        }
    }

    // --- VIEW 1: ANGLE 0.0 (Frontal Truth) ---
    let mut v1_data = vec![0u8; width * height];
    let v1_stub = ProjectionView {
        view_id: "v1".into(),
        angle_rad: 0.0,
        frame_data: Vec::new(),
        width,
        height,
    };
    for &coord in &truth_voxels {
        let (u, v) = VirtualShutter::project(coord, &v1_stub, center);
        if u < width && v < height {
            v1_data[v * width + u] = 255;
        }
    }
    let view1 = ProjectionView {
        view_id: "v1".into(),
        angle_rad: 0.0,
        frame_data: v1_data,
        width,
        height,
    };

    // --- VIEW 2: ANGLE 0.8 (Side Truth) ---
    let mut v2_data = vec![0u8; width * height];
    let v2_stub = ProjectionView {
        view_id: "v2".into(),
        angle_rad: 0.8,
        frame_data: Vec::new(),
        width,
        height,
    };
    for &coord in &truth_voxels {
        let (u, v) = VirtualShutter::project(coord, &v2_stub, center);
        if u < width && v < height {
            v2_data[v * width + u] = 255;
        }
    }
    let view2 = ProjectionView {
        view_id: "v2".into(),
        angle_rad: 0.8,
        frame_data: v2_data,
        width,
        height,
    };

    // --- VIEW 3: SABOTEUR (Angle 1.5, but shifted offset) ---
    // The Saboteur projects a DIFFERENT shape (a pillar) hoping to poison the mesh.
    let mut v3_data = vec![0u8; width * height];
    let v3_stub = ProjectionView {
        view_id: "v3".into(),
        angle_rad: 1.5,
        frame_data: Vec::new(),
        width,
        height,
    };
    // Saboteur Pillar at x=5, y=5
    for z in 0..40 {
        let sab_coord = VoxelCoord { x: 5, y: 5, z };
        let (u, v) = VirtualShutter::project(sab_coord, &v3_stub, center);
        if u < width && v < height {
            v3_data[v * width + u] = 255;
        }
    }
    let _view3 = ProjectionView {
        view_id: "v3".into(),
        angle_rad: 1.5,
        frame_data: v3_data,
        width,
        height,
    };

    println!(" [ STAGE 1: INGESTING TRUTH VIEWS ] ");
    sieve.reconstruct(&[view1, view2]);
    let truth_count = sieve.space.voxels.len();
    println!(" Reconstructed Voxels: {}", truth_count);

    println!(" [ STAGE 2: INGESTING SABOTEUR VIEW ] ");
    // Re-run reconstruction with all 3 views.
    // The intersection logic (Sovereign Sieve) should REJECT the Saboteur's pillar
    // because it doesn't exist in views 1 and 2.

    let v1 = ProjectionView {
        view_id: "v1".into(),
        angle_rad: 0.0,
        frame_data: view_stub_data(&truth_voxels, 0.0, center, width, height),
        width,
        height,
    };
    let v2 = ProjectionView {
        view_id: "v2".into(),
        angle_rad: 0.8,
        frame_data: view_stub_data(&truth_voxels, 0.8, center, width, height),
        width,
        height,
    };
    let v3 = ProjectionView {
        view_id: "v3".into(),
        angle_rad: 1.5,
        frame_data: v3_pillar_data(center, width, height),
        width,
        height,
    };

    sieve.reconstruct(&[v1, v2, v3]);
    let final_count = sieve.space.voxels.len();
    println!(" Final Consensus Voxels: {}", final_count);

    if final_count <= truth_count {
        println!(
            " [ VALIDATION PASSED ] Saboteur noise discarded via Multi-Perspective Consensus."
        );
    } else {
        println!(" [ VALIDATION FAILED ] Saboteur noise polluted the manifold!");
    }

    Ok(())
}

fn view_stub_data(
    voxels: &[VoxelCoord],
    angle: f32,
    center: VoxelCoord,
    width: usize,
    height: usize,
) -> Vec<u8> {
    let mut data = vec![0u8; width * height];
    let stub = ProjectionView {
        view_id: "s".into(),
        angle_rad: angle,
        frame_data: Vec::new(),
        width,
        height,
    };
    for &coord in voxels {
        let (u, v) = VirtualShutter::project(coord, &stub, center);
        if u < width && v < height {
            data[v * width + u] = 255;
        }
    }
    data
}

fn v3_pillar_data(center: VoxelCoord, width: usize, height: usize) -> Vec<u8> {
    let mut data = vec![0u8; width * height];
    let stub = ProjectionView {
        view_id: "s".into(),
        angle_rad: 1.5,
        frame_data: Vec::new(),
        width,
        height,
    };
    for z in 0..40 {
        let (u, v) = VirtualShutter::project(VoxelCoord { x: 5, y: 5, z }, &stub, center);
        if u < width && v < height {
            data[v * width + u] = 255;
        }
    }
    data
}
